// iconPaths returns the path data for the given icon name, split into individual paths.
// Unknown names fall back to the Question icon — safe default that visually signals
// "something is wrong" without crashing render.
// Panics if path data contains empty segments (consecutive or trailing "|" separators).
func iconPaths(name Name) []string {
	d, ok := iconPathData[name]
	if !ok {
		d = iconPathData[Question]
	}
	parts := strings.Split(d, "|")
	for _, p := range parts {
		if p == "" {
			panic(fmt.Sprintf("icons: icon %q has empty path segment — check for stray | separator", name))
		}
	}
	return parts
}

// IconPathData returns the raw SVG path d-attribute strings for the given icon.
// Use this when you need full control over the <svg> wrapper element (e.g. custom
// class, stroke-width, or viewBox). Unknown names fall back to Question.
//
//	for _, d := range icons.IconPathData(icons.Users) {
//	    fmt.Printf(`<path d="%s"/>`, d)
//	}
func IconPathData(name Name) []string {
	return iconPaths(name)
}

// IconPathJS returns the inner HTML for an SVG icon path element,
// suitable for use in JavaScript-generated icons.
func IconPathJS(name Name) string {
	paths := iconPaths(name)
	var b strings.Builder
	for _, p := range paths {
		b.WriteString(`<path stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5" d="`)
		b.WriteString(p)
		b.WriteString(`"/>`)
	}
	return b.String()
}
